import { createRouter, createWebHistory } from 'vue-router'
import Home from '../views/Home.vue'
import EnterpriseTechTool from '../views/EnterpriseTechTool.vue'
import LightingControlApp from '../views/LightingControlApp.vue'
import UIDesign from '../views/UIDesign.vue'
import GivingMVP from '../views/GivingMVP.vue'
import ECommerce from '../views/ECommerce.vue'

const routes = [
  {
    path: '/',
    name: 'Home',
    component: Home
  },
  {
    path: '/ux-portfolio/enterprise-tech-support-tool',
    name: 'Enterprise Tech Support Tool',
    component: EnterpriseTechTool
  },
  {
    path: '/ux-portfolio/lighting-control-application',
    name: 'Lighting Control Application',
    component: LightingControlApp
  },
  {
    path: '/ux-portfolio/ui-design',
    name: 'UI Design Samples',
    component: UIDesign
  },
  {
    path: '/ux-portfolio/giving-research-mvp',
    name: 'Giving Research MVP',
    component: GivingMVP
  },
  {
    path: '/ux-portfolio/ecommerce-usability-study',
    name: 'E-Commerce Usability and Optimization',
    component: ECommerce
  }
]

const router = createRouter({
  mode: 'history',
  history: createWebHistory(process.env.BASE_URL),
  routes,
  scrollBehavior (to, from, savedPosition) {
    if (savedPosition && to.path=='/') {
      console.log(savedPosition)
      return savedPosition
    } else {
      console.log('scroll to top')
      document.getElementById('top').scrollIntoView();
      return { x: 0, y: 0 }
    }
  }
})

export default router
